        if (msg.ctrl_mod)doc["ctrl_mod"] = *msg.ctrl_mod;
        if (msg.ctrl_typ)doc["ctrl_typ"] = *msg.ctrl_typ;
        if (msg.cur_mot_max)doc["cur_mot_max"] = *msg.cur_mot_max;
